1: import Cocoa
2: 
3: private let syntheticTag: Int64 = 0x4C4558
4: 
5: class AppDelegate: NSObject, NSApplicationDelegate {
6:     var statusItem: NSStatusItem!
7:     var eventTap: CFMachPort?
8:     var syntheticSource: CGEventSource?
9: 
10:     func applicationDidFinishLaunching(_ notification: Notification) {
11:         syntheticSource = CGEventSource(stateID: .privateState)
12:         syntheticSource?.userData = syntheticTag
13:         setupMenuBar()
14:         requestAccessAndStartTap()
15:         observeAppSwitch()
16:     }
17: 
18:     private func setupMenuBar() {
19:         statusItem = NSStatusBar.system.statusItem(withLength: NSStatusItem.variableLength)
20:         if let button = statusItem.button {
21:             button.title = "⌨"
22:         }
23:         let menu = NSMenu()
24:         menu.addItem(NSMenuItem(title: "Exit", action: #selector(NSApplication.terminate(_:)), keyEquivalent: "q"))
25:         statusItem.menu = menu
26:     }
27: 
28:     private func requestAccessAndStartTap() {
29:         let options = [kAXTrustedCheckOptionPrompt.takeUnretainedValue(): true] as CFDictionary
30:         if !AXIsProcessTrustedWithOptions(options) {
31:             print("Accessibility permission required. Please grant access in System Settings > Privacy & Security > Accessibility, then relaunch.")
32:             return
33:         }
34:         startEventTap()
35:     }
36: 
37:     private func observeAppSwitch() {
38:         NSWorkspace.shared.notificationCenter.addObserver(
39:             forName: NSWorkspace.didActivateApplicationNotification,
40:             object: nil,
41:             queue: .main
42:         ) { _ in
43:             reset_state()
44:         }
45:     }
46: 
47:     private func startEventTap() {
48:         let eventMask: CGEventMask = (1 << CGEventType.keyDown.rawValue)
49:             | (1 << CGEventType.flagsChanged.rawValue)
50:             | (1 << CGEventType.tapDisabledByTimeout.rawValue)
51:             | (1 << CGEventType.tapDisabledByUserInput.rawValue)
52: 
53:         let selfPtr = Unmanaged.passUnretained(self).toOpaque()
54: 
55:         guard let tap = CGEvent.tapCreate(
56:             tap: .cgSessionEventTap,
57:             place: .headInsertEventTap,
58:             options: .defaultTap,
59:             eventsOfInterest: eventMask,
60:             callback: eventTapCallback,
61:             userInfo: selfPtr
62:         ) else {
63:             print("Failed to create event tap. Ensure Input Monitoring permission is granted.")
64:             return
65:         }
66: 
67:         eventTap = tap
68:         let runLoopSource = CFMachPortCreateRunLoopSource(kCFAllocatorDefault, tap, 0)
69:         CFRunLoopAddSource(CFRunLoopGetCurrent(), runLoopSource, .commonModes)
70:         CGEvent.tapEnable(tap: tap, enable: true)
71:         print("Event tap started.")
72:     }
73: 
74:     func emitSyntheticEvents(result: ProcessKeyEventResult) {
75:         guard let source = syntheticSource else { return }
76: 
77:         for _ in 0..<result.num_backspaces {
78:             if let down = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: true),
79:                let up = CGEvent(keyboardEventSource: source, virtualKey: 0x33, keyDown: false) {
80:                 down.post(tap: .cgSessionEventTap)
81:                 up.post(tap: .cgSessionEventTap)
82:             }
83:         }
84: 
85:         for i in 0..<Int(result.num_chars) {
86:             var char = result.chars[i]
87:             if let down = CGEvent(keyboardEventSource: source, virtualKey: 0, keyDown: true),
88:                let up = CGEvent(keyboardEventSource: source, virtualKey: 0, keyDown: false) {
89:                 down.keyboardSetUnicodeString(stringLength: 1, unicodeString: &char)
90:                 up.keyboardSetUnicodeString(stringLength: 1, unicodeString: &char)
91:                 down.post(tap: .cgSessionEventTap)
92:                 up.post(tap: .cgSessionEventTap)
93:             }
94:         }
95:     }
96: }
97: 
98: func eventTapCallback(
99:     proxy: CGEventTapProxy,
100:     type eventType: CGEventType,
101:     event: CGEvent,
102:     userInfo: UnsafeMutableRawPointer?
103: ) -> Unmanaged<CGEvent>? {
104:     guard let userInfo = userInfo else {
105:         return Unmanaged.passUnretained(event)
106:     }
107:     let appDelegate = Unmanaged<AppDelegate>.fromOpaque(userInfo).takeUnretainedValue()
108: 
109:     if eventType == .tapDisabledByTimeout || eventType == .tapDisabledByUserInput {
110:         if let tap = appDelegate.eventTap {
111:             CGEvent.tapEnable(tap: tap, enable: true)
112:         }
113:         reset_state()
114:         return Unmanaged.passUnretained(event)
115:     }
116: 
117:     if eventType == .flagsChanged {
118:         return Unmanaged.passUnretained(event)
119:     }
120: 
121:     guard eventType == .keyDown else {
122:         return Unmanaged.passUnretained(event)
123:     }
124: 
125:     if event.getIntegerValueField(.eventSourceUserData) == syntheticTag {
126:         return Unmanaged.passUnretained(event)
127:     }
128: 
129:     let flags = event.flags
130:     let modifierMask: CGEventFlags = [.maskCommand, .maskControl, .maskAlternate]
131:     if !flags.intersection(modifierMask).isEmpty {
132:         reset_state()
133:         return Unmanaged.passUnretained(event)
134:     }
135: 
136:     let keyCode = event.getIntegerValueField(.keyboardEventKeycode)
137:     if keyCode == 0x33 {
138:         let _ = process_backspace()
139:         return Unmanaged.passUnretained(event)
140:     }
141: 
142:     var charCount: Int = 0
143:     event.keyboardGetUnicodeString(maxStringLength: 0, actualStringLength: &charCount, unicodeString: nil)
144: 
145:     guard charCount == 1 else {
146:         reset_state()
147:         return Unmanaged.passUnretained(event)
148:     }
149: 
150:     var unicodeChar: UniChar = 0
151:     event.keyboardGetUnicodeString(maxStringLength: 1, actualStringLength: &charCount, unicodeString: &unicodeChar)
152: 
153:     let result = process_key_event(unicodeChar)
154: 
155:     if result.swallow_event {
156:         appDelegate.emitSyntheticEvents(result: result)
157:         return nil
158:     }
159: 
160:     return Unmanaged.passUnretained(event)
161: }
162: 
163: let app = NSApplication.shared
164: app.setActivationPolicy(.accessory)
165: 
166: let delegate = AppDelegate()
167: app.delegate = delegate
168: app.run()

1: #ifndef MINIMAL_BRIDGING_HEADER_H
2: #define MINIMAL_BRIDGING_HEADER_H
3: 
4: #include <stdint.h>
5: #include <stdbool.h>
6: 
7: typedef struct {
8:     uint8_t num_backspaces;
9:     uint8_t num_chars;
10:     bool swallow_event;
11:     const uint16_t *chars;
12: } ProcessKeyEventResult;
13: 
14: ProcessKeyEventResult process_key_event(uint16_t char_code);
15: ProcessKeyEventResult process_backspace(void);
16: void reset_state(void);
17: 
18: #endif

1: const State = enum(u8) {
2:     idle,
3:     one_e,
4:     circumflex,
5:     literal,
6: };
7: 
8: const ProcessKeyEventResult = extern struct {
9:     num_backspaces: u8,
10:     num_chars: u8,
11:     swallow_event: bool,
12:     chars: [*]const u16,
13: };
14: 
15: // --- Internal variables ---
16: 
17: var state: State = .idle;
18: var first_e_upper: bool = false;
19: var gap: u8 = 0;
20: var bufs: [2][2]u16 = .{ .{ 0, 0 }, .{ 0, 0 } };
21: var active: u1 = 0;
22: 
23: const passthrough: ProcessKeyEventResult = .{
24:     .num_backspaces = 0,
25:     .num_chars = 0,
26:     .swallow_event = false,
27:     .chars = @ptrCast(&bufs[0]),
28: };
29: 
30: // --- Internal functions ---
31: 
32: fn emit(num_backspaces: u8, chars: []const u16) ProcessKeyEventResult {
33:     const buf = @as([*]u16, @ptrCast(&bufs[active]));
34:     for (chars, 0..) |c, i| buf[i] = c;
35:     active ^= 1;
36:     return .{
37:         .num_backspaces = num_backspaces,
38:         .num_chars = @intCast(chars.len),
39:         .swallow_event = true,
40:         .chars = buf,
41:     };
42: }
43: 
44: fn is_e(c: u16) bool {
45:     return c == 'e' or c == 'E';
46: }
47: 
48: fn is_alphanumeric(c: u16) bool {
49:     return (c >= '0' and c <= '9') or
50:         (c >= 'A' and c <= 'Z') or
51:         (c >= 'a' and c <= 'z');
52: }
53: 
54: fn handle_e(char_code: u16) ProcessKeyEventResult {
55:     const upper = char_code == 'E';
56:     switch (state) {
57:         .idle => {
58:             state = .one_e;
59:             first_e_upper = upper;
60:             return passthrough;
61:         },
62:         .one_e => {
63:             state = .circumflex;
64:             const c: u16 = if (first_e_upper) 0x00CA else 0x00EA;
65:             return emit(1, &.{c});
66:         },
67:         .circumflex => {
68:             state = .literal;
69:             const c0: u16 = if (first_e_upper) 'E' else 'e';
70:             const c1: u16 = if (upper) 'E' else 'e';
71:             return emit(1, &.{ c0, c1 });
72:         },
73:         .literal => unreachable,
74:     }
75: }
76: 
77: // --- Public functions ---
78: 
79: export fn reset_state() void {
80:     state = .idle;
81:     first_e_upper = false;
82:     gap = 0;
83: }
84: 
85: export fn process_backspace() ProcessKeyEventResult {
86:     if (gap > 0) {
87:         gap -= 1;
88:     } else switch (state) {
89:         .literal => state = .one_e,
90:         .idle => {},
91:         else => reset_state(),
92:     }
93:     return passthrough;
94: }
95: 
96: export fn process_key_event(char_code: u16) ProcessKeyEventResult {
97:     if (is_e(char_code)) {
98:         if (gap == 0 and state != .literal) return handle_e(char_code);
99:     } else if (!is_alphanumeric(char_code)) {
100:         reset_state();
101:         return passthrough;
102:     } else if (state == .idle) {
103:         return passthrough;
104:     }
105: 
106:     if (gap == 255) {
107:         reset_state();
108:         return passthrough;
109:     }
110:     gap += 1;
111:     return passthrough;
112: }
